package jobs

import (
    "context"
    "log"
    "time"

    "github.com/Q9Labs/chalk/internal/domain/recording"
    "github.com/Q9Labs/chalk/internal/infrastructure/cloudflare"
    "github.com/Q9Labs/chalk/internal/infrastructure/postgres/db"
)

type RecordingChecker struct {
    db       *db.Queries
    cfClient *cloudflare.Client
    recSvc   *recording.Service
}

func NewRecordingChecker(queries *db.Queries, cf *cloudflare.Client, recSvc *recording.Service) *RecordingChecker {
    return &RecordingChecker{db: queries, cfClient: cf, recSvc: recSvc}
}

func (c *RecordingChecker) CheckStalledRecordings(ctx context.Context) error {
    // Find recordings stuck in 'processing' for > 1 hour
    recordings, err := c.db.ListRecordingsByStatus(ctx, db.ListRecordingsByStatusParams{
        Status: "processing",
        Limit:  100,
        Offset: 0,
    })
    if err != nil {
        return err
    }

    for _, rec := range recordings {
        // Check if updated more than 1 hour ago
        if time.Since(rec.CreatedAt) < 1*time.Hour {
            continue // Still processing, give it time
        }

        log.Printf("Checking stalled recording: %s", rec.ID)

        // Poll Cloudflare for actual status
        if rec.CloudflareRecordingID != nil {
            cfRec, err := c.cfClient.GetRecording(ctx, *rec.CloudflareRecordingID)
            if err != nil {
                log.Printf("Cloudflare API error for %s: %v", rec.ID, err)
                // Mark as failed after multiple retries
                continue
            }

            if cfRec.Status == "ready" {
                log.Printf("Recording %s ready in Cloudflare but webhook missed!", rec.ID)
                // TODO: Process manually - download and upload to R2
            } else if cfRec.Status == "failed" {
                log.Printf("Recording %s failed in Cloudflare", rec.ID)
                // Mark as failed in DB
                _, _ = c.db.MarkRecordingFailed(ctx, rec.ID)
            }
        }
    }

    return nil
}

// Run starts the checker on a schedule
func (c *RecordingChecker) Run(ctx context.Context, interval time.Duration) {
    ticker := time.NewTicker(interval)
    defer ticker.Stop()

    for {
        select {
        case <-ticker.C:
            if err := c.CheckStalledRecordings(ctx); err != nil {
                log.Printf("Recording check error: %v", err)
            }
        case <-ctx.Done():
            return
        }
    }
}

