locals {
  whiteboard_port = 80
}

resource "aws_ecs_task_definition" "whiteboard" {
  count = var.create_whiteboard_service ? 1 : 0

  family                   = "${local.name}-whiteboard"
  network_mode             = "awsvpc"
  requires_compatibilities = ["EC2"]
  cpu                      = var.whiteboard_task_cpu
  memory                   = var.whiteboard_task_memory
  execution_role_arn       = aws_iam_role.ecs_task_execution.arn
  task_role_arn            = aws_iam_role.ecs_task.arn

  container_definitions = jsonencode([
    {
      name  = "whiteboard"
      image = "excalidraw/excalidraw-room:latest"

      portMappings = [
        {
          containerPort = local.whiteboard_port
          hostPort      = local.whiteboard_port
          protocol      = "tcp"
        }
      ]

      environment = [
        { name = "PORT", value = tostring(local.whiteboard_port) }
      ]

      logConfiguration = {
        logDriver = "awslogs"
        options = {
          "awslogs-group"         = aws_cloudwatch_log_group.ecs.name
          "awslogs-region"        = data.aws_region.current.name
          "awslogs-stream-prefix" = "whiteboard"
        }
      }

      essential = true
    }
  ])

  tags = local.tags
}

resource "aws_lb_target_group" "whiteboard" {
  count = var.create_whiteboard_service ? 1 : 0

  name        = "${local.name}-whiteboard"
  port        = local.whiteboard_port
  protocol    = "HTTP"
  vpc_id      = var.vpc_id
  target_type = "ip"

  health_check {
    enabled             = true
    healthy_threshold   = 2
    unhealthy_threshold = 3
    interval            = 30
    path                = "/"
    port                = "traffic-port"
    protocol            = "HTTP"
    timeout             = 5
    matcher             = "200-399"
  }

  tags = local.tags
}

resource "aws_lb_listener_rule" "whiteboard" {
  count = var.create_whiteboard_service && var.enable_https_listener ? 1 : 0

  listener_arn = aws_lb_listener.https[0].arn
  priority     = 100

  action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.whiteboard[0].arn
  }

  condition {
    path_pattern {
      values = ["/whiteboard/*", "/socket.io/*"]
    }
  }

  tags = local.tags
}

resource "aws_ecs_service" "whiteboard" {
  count = var.create_whiteboard_service ? 1 : 0

  name            = "${local.name}-whiteboard"
  cluster         = aws_ecs_cluster.main.id
  task_definition = aws_ecs_task_definition.whiteboard[0].arn
  desired_count   = 1

  capacity_provider_strategy {
    base              = 0
    weight            = 100
    capacity_provider = aws_ecs_capacity_provider.main.name
  }

  network_configuration {
    subnets         = var.private_subnet_ids
    security_groups = [aws_security_group.ecs_tasks[0].id]
  }

  load_balancer {
    target_group_arn = aws_lb_target_group.whiteboard[0].arn
    container_name   = "whiteboard"
    container_port   = local.whiteboard_port
  }

  tags = local.tags
}

